// Full-duplex audio capture with AEC, noise suppression, and gain control.
// The browser's WebRTC AEC uses the system audio output as the reference
// signal automatically — no manual reference wiring required.

async function startFullDuplexCapture() {
  const stream = await navigator.mediaDevices.getUserMedia({
    audio: {
      echoCancellation: true,       // WebRTC NLMS AEC
      noiseSuppression: true,       // spectral subtraction
      autoGainControl: true,        // microphone level normalisation
      sampleRate: 24000,            // match the Realtime API sample rate
      channelCount: 1,              // mono
    },
  });

  const audioCtx = new AudioContext({ sampleRate: 24000 });
  const source   = audioCtx.createMediaStreamSource(stream);

  // ScriptProcessor (legacy) or AudioWorkletNode for low-latency PCM access.
  // AudioWorklet is preferred in production — ScriptProcessor is deprecated.
  await audioCtx.audioWorklet.addModule('/worklets/pcm-capture.js');
  const captureNode = new AudioWorkletNode(audioCtx, 'pcm-capture', {
    processorOptions: { chunkSizeMs: 20, sampleRate: 24000 },
  });

  captureNode.port.onmessage = ({ data }) => {
    // data.pcm16 is a Int16Array of 20 ms of cleaned, echo-cancelled audio.
    // Encode to base64 and append to the Realtime API input_audio_buffer.
    const base64 = int16ToBase64(data.pcm16);
    realtimeSocket.send(JSON.stringify({
      type: 'input_audio_buffer.append',
      audio: base64,
    }));
  };

  source.connect(captureNode);
  captureNode.connect(audioCtx.destination); // required by the graph spec

  return { stream, audioCtx, captureNode };
}

function int16ToBase64(int16Array) {
  const bytes = new Uint8Array(int16Array.buffer);
  let binary = '';
  for (let i = 0; i < bytes.byteLength; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

// ----- Interrupt handling on the client -----
// The Realtime API fires 'response.cancelled' when the server stops a response.
// Stop the TTS audio player immediately so the agent goes silent.

function handleRealtimeEvent(event, ttsPlayer) {
  switch (event.type) {
    case 'input_audio_buffer.speech_started':
      // VAD detected user speech — server will cancel the active response.
      console.log('[barge-in] speech detected at', event.audio_start_ms, 'ms');
      break;

    case 'response.cancelled':
      // Agent response was cancelled — stop playback immediately.
      ttsPlayer.stop();
      console.log('[barge-in] response cancelled, user has the floor');
      break;

    case 'conversation.item.truncated':
      // Audio buffer was cut. event.audio_end_ms tells us how much played.
      console.log('[barge-in] audio truncated at', event.audio_end_ms, 'ms');
      break;
  }
}
